module top_module(
	input [31:0] inALUOut,
	input reset, clk,
	output [31:0] outALUOut
    );reg [31:0] misleading_registerALUOut;

	assign outALUOut = misleading_registerALUOut;

	always@(posedge clk)
		begin
			if (reset)
				begin
					misleading_registerALUOut <= 32'b0;
				end
			else
				begin
					misleading_registerALUOut <= inALUOut;
				end
		end

endmodule
